#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding diabetes-assessment (15 tables)..."

cargo loco generate scaffold patient \
    full_name:text! \
    date_of_birth:date \
    nhs_number:text! \
    address:text! \
    telephone:text! \
    email:text! \
    gp_name:text! \
    gp_practice:text! \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:text! \
    --htmx

cargo loco generate scaffold assessment_diabetes_history \
    assessment:references \
    diabetes_type:text! \
    age_at_diagnosis:int \
    years_duration:int \
    diagnosis_method:text! \
    family_history:text! \
    autoantibodies_tested:text! \
    --htmx

cargo loco generate scaffold assessment_glycaemic_control \
    assessment:references \
    hba1c_value:double \
    hba1c_unit:text! \
    hba1c_target:double \
    fasting_glucose:double \
    postprandial_glucose:double \
    glucose_monitoring_type:text! \
    hypoglycaemia_frequency:text! \
    severe_hypoglycaemia:text! \
    time_in_range:double \
    --htmx

cargo loco generate scaffold assessment_medications \
    assessment:references \
    metformin:text! \
    sulfonylurea:text! \
    sglt2_inhibitor:text! \
    glp1_agonist:text! \
    dpp4_inhibitor:text! \
    insulin:text! \
    insulin_regimen:text! \
    insulin_daily_dose:double \
    medication_adherence:int \
    other_medications:text! \
    --htmx

cargo loco generate scaffold assessment_complications_screening \
    assessment:references \
    retinopathy_status:text! \
    last_eye_screening:date \
    nephropathy_status:text! \
    egfr:double \
    urine_acr:double \
    neuropathy_symptoms:text! \
    autonomic_neuropathy:text! \
    erectile_dysfunction:text! \
    --htmx

cargo loco generate scaffold assessment_cardiovascular_risk \
    assessment:references \
    systolic_bp:int \
    diastolic_bp:int \
    on_antihypertensive:text! \
    total_cholesterol:double \
    ldl_cholesterol:double \
    on_statin:text! \
    smoking_status:text! \
    previous_cvd_event:text! \
    qrisk_score:double \
    --htmx

cargo loco generate scaffold assessment_self_care_lifestyle \
    assessment:references \
    diet_adherence:int \
    carb_counting:text! \
    physical_activity:text! \
    bmi:double \
    weight_change:text! \
    alcohol_consumption:text! \
    smoking_cessation:text! \
    --htmx

cargo loco generate scaffold assessment_psychological_wellbeing \
    assessment:references \
    diabetes_distress:int \
    depression_screening:int \
    anxiety_screening:int \
    eating_disorder:text! \
    fear_of_hypoglycaemia:int \
    coping_ability:int \
    needs_support:text! \
    --htmx

cargo loco generate scaffold assessment_foot_assessment \
    assessment:references \
    foot_pulses:text! \
    monofilament_test:text! \
    vibration_sense:text! \
    foot_deformity:text! \
    callus_present:text! \
    ulcer_present:text! \
    previous_amputation:text! \
    foot_risk_category:text! \
    --htmx

cargo loco generate scaffold assessment_review_care_plan \
    assessment:references \
    clinician_name:text! \
    review_date:date \
    hba1c_target_agreed:double \
    care_plan_updated:text! \
    clinical_notes:text! \
    referrals:text! \
    next_review_date:date \
    --htmx

cargo loco generate scaffold diabetes_rule \
    category:text! \
    description:text! \
    concern_level:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    control_level:text! \
    control_score:int! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    diabetes_rule:references \
    rule_category:text! \
    rule_description:text! \
    rule_concern_level:text! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:text! \
    category:text! \
    message:text! \
    priority:text! \
    --htmx

echo "Done."
